<?php
namespace App\Services\Security;
use App\Models\{SecurityGovernanceNotification,User};use Carbon\Carbon;
class SecurityGovernanceSlaService{public function assignSla($n,User $a,Carbon $dueAt,?User $owner,string $reason){$n->update(['sla_due_at'=>$dueAt,'sla_status'=>'open','escalation_owner_id'=>$owner?->id,'last_sla_checked_at'=>now()]);$n->events()->create(['actor_id'=>$a->id,'event_type'=>'sla_due_set','description'=>$reason,'created_at'=>now()]);return $n->refresh();}public function evaluateSla($n):array{if($n->status==='resolved')return ['status'=>'resolved'];$status=$n->sla_due_at?->isPast()?($n->severity==='critical'?'breached':'overdue'):($n->sla_due_at&&$n->sla_due_at->diffInHours(now())<=24?'due_soon':'open');return ['status'=>$status];}public function runSlaCheck(?User $a=null,bool $dryRun=false):array{$counts=['checked'=>0,'due_soon'=>0,'overdue'=>0,'breached'=>0];SecurityGovernanceNotification::whereIn('status',['open','acknowledged'])->each(function($n)use($a,$dryRun,&$counts){$status=$this->evaluateSla($n)['status'];$counts['checked']++;if(isset($counts[$status]))$counts[$status]++;if(!$dryRun&&$status!==$n->sla_status){$n->update(['sla_status'=>$status,'last_sla_checked_at'=>now()]);$n->events()->create(['actor_id'=>$a?->id,'event_type'=>'sla_'.$status,'description'=>'Database-only SLA evaluation; no external notification sent.','created_at'=>now()]);}});return $counts;}public function escalateBreached($n,?User $a=null){return app(SecurityGovernanceNotificationService::class)->escalate($n,$a,'SLA breached.');}}
